import requests
from typing import Dict, Any, Optional
import json

def fetch_and_display_url_content(url: str, headers: Optional[Dict[str, str]] = None, timeout: int = 30) -> Dict[str, Any]:
    """
    Fetches and displays content from a given URL.
    
    Args:
        url (str): The URL to fetch content from
        headers (dict, optional): HTTP headers to include in the request
        timeout (int): Request timeout in seconds
        
    Returns:
        dict: Response data including status, content, and metadata
    """
    try:
        response = requests.get(
            url, 
            headers=headers, 
            timeout=timeout
        )
        response.raise_for_status()
        
        content_type = response.headers.get('content-type', '')
        content = response.text
        
        # Try to parse as JSON if content-type suggests it
        if 'application/json' in content_type:
            try:
                content = response.json()
            except json.JSONDecodeError:
                pass
        
        return {
            'status': 'success',
            'url': url,
            'status_code': response.status_code,
            'content_type': content_type,
            'content': content,
            'headers': dict(response.headers)
        }
        
    except requests.exceptions.RequestException as e:
        return {
            'status': 'error',
            'url': url,
            'error': str(e),
            'error_type': type(e).__name__
        }

def process_webhook_payload(payload: Dict[str, Any], integration_type: str) -> Dict[str, Any]:
    """
    Process webhook payload based on integration type.
    
    Args:
        payload (dict): The webhook payload
        integration_type (str): Type of integration (e.g., 'slack', 'webhook', 'api')
        
    Returns:
        dict: Processed payload with content fetched if needed
    """
    processed_payload = {
        'integration_type': integration_type,
        'payload': payload,
        'processed_at': 'timestamp_placeholder'
    }
    
    # Handle different integration types
    if integration_type == 'webhook':
        # Example: Fetch content from URL if present in payload
        if 'url' in payload:
            content_result = fetch_and_display_url_content(payload['url'])
            processed_payload['content'] = content_result
            
    elif integration_type == 'api':
        # Example: Process API response
        if 'api_endpoint' in payload:
            api_result = fetch_and_display_url_content(payload['api_endpoint'])
            processed_payload['api_response'] = api_result
            
    return processed_payload

# Example usage for webhook processing
def handle_webhook(webhook_data: Dict[str, Any], integration_config: Dict[str, Any]) -> Dict[str, Any]:
    """
    Main function to handle webhook data with flexible integration support.
    
    Args:
        webhook_data (dict): Raw webhook data
        integration_config (dict): Configuration for the integration
        
    Returns:
        dict: Processed webhook result
    """
    integration_type = integration_config.get('type', 'webhook')
    
    # Process the webhook based on integration type
    result = process_webhook_payload(webhook_data, integration_type)
    
    # Add integration metadata
    result['integration_config'] = integration_config
    
    return result